content.text:
add all these MCP servers (the ones that aren't connected yet) to my Codex for windows: 
{
  "mcpServers": {
    "ag-grid": {
      "command": "npx",
      "args": [
        "-y",
        "ag-mcp"
      ]
    },
    "playwright": {
      "command": "C:\\PROGRA~1\\nodejs\\npx.cmd",
      "args": [
        "-y",
        "@playwright/mcp@latest"
      ]
    },
    "synology-monitor": {
      "command": "C:\\PROGRA~1\\nodejs\\npx.cmd",
      "args": [
        "-y",
        "mcp-remote@latest",
        "https://nas-mcp.designflow.app/mcp",
        "--transport",
        "http-first",
        "--header",
        "Authorization: Bearer [REDACTED_BEARER_TOKEN]"
      ]
    },
    "devops-mcp": {
      "command": "C:\\PROGRA~1\\nodejs\\npx.cmd",
      "args": [
        "-y",
        "mcp-remote@latest",
        "https://mcp.designflow.app/mcp",
        "--transport",
        "http-first",
        "--header",
        "Authorization: Bearer [REDACTED_BEARER_TOKEN]"
      ]
    }
  }

